import pytest
import torch

from . import base, consts

# Shapes for permute_copy benchmark: (original_shape, dims)
PERMUTE_COPY_SHAPES = [
    ((64, 128), (1, 0)),
    ((128, 256), (0, 1)),
    ((32, 64, 128), (2, 0, 1)),
]


class PermuteCopyBenchmark(base.Benchmark):
    def set_shapes(self, shape_file_path=None):
        self.shapes = PERMUTE_COPY_SHAPES

    def get_input_iter(self, cur_dtype):
        for shape, dims in self.shapes:
            x = torch.randn(shape, dtype=cur_dtype, device=self.device)
            yield x, dims


@pytest.mark.permute_copy
def test_permute_copy():
    bench = PermuteCopyBenchmark(
        op_name="permute_copy",
        torch_op=torch.permute_copy,
        dtypes=consts.FLOAT_DTYPES,
    )
    bench.run()
